#include <iostream>
using namespace std;

int main() {
  int a = 10, b = 3;
  cout << "Sum: " << (a + b) << endl;
  cout << "Product: " << (a * b) << endl;
  cout << "Division: " << (a / b) << endl;
  cout << "Modulus: " << (a % b) << endl;
  cout << "Increment: " << ++a << endl;
  return 0;
}
